import{_ as e,c as l,o as a,a as i}from"./app.87b1f767.js";const S=JSON.parse('{"title":"SQL","description":"","frontmatter":{},"headers":[{"level":2,"title":"SQL 分类","slug":"sql-分类","link":"#sql-分类","children":[]},{"level":2,"title":"SQL 基本语法","slug":"sql-基本语法","link":"#sql-基本语法","children":[]}],"relativePath":"mysql/sql.md"}'),t={name:"mysql/sql.md"},o=i('<h1 id="sql" tabindex="-1">SQL <a class="header-anchor" href="#sql" aria-hidden="true">#</a></h1><p>SQL（Structured Query Language）结构化查询语言，用于存取、查询、更新数据以及管理关系型数据库</p><h2 id="sql-分类" tabindex="-1">SQL 分类 <a class="header-anchor" href="#sql-分类" aria-hidden="true">#</a></h2><blockquote><p>根据 SQL 指令完成的数据库操作不同，可以将 SQL 分为四类</p></blockquote><ul><li><code>DDL</code> Data Definition Language 数据定义语言 <ul><li>用于完成对数据库对象（数据库、数据表、视图、索引等）的创建、删除、修改</li></ul></li><li><code>DML</code> Data Manipulation Language 数据操作语言 <ul><li>用于完成对数据表中的数据的添加、删除、修改等操作</li></ul></li><li><code>DQL</code> Data Query Language 数据查询语言 <ul><li>用于将数据表中的数据查询出来</li></ul></li><li><code>DCL</code> Data Control Language 数据控制语言 <ul><li>用于完成事务管理等控制性操作</li></ul></li></ul><h2 id="sql-基本语法" tabindex="-1">SQL 基本语法 <a class="header-anchor" href="#sql-基本语法" aria-hidden="true">#</a></h2><ul><li>SQL 指令不区分大小写</li><li>每条 SQL 指令结束以后都有 <code>;</code> 结尾</li><li>SQL 指令以 <code>空格</code> 进行分割</li><li>SQL 直接可以不限制换行（关键字直接以空格进行分隔）</li></ul>',7),s=[o];function c(d,n,r,u,_,h){return a(),l("div",null,s)}const q=e(t,[["render",c]]);export{S as __pageData,q as default};
